-- VKD kahraman sayfalari: turk-dunyasi-kahramanlari icerigi + vefa-galerisi sayfasi ve menu
DO $$
DECLARE
  pages jsonb;
  menu jsonb;
  upd record;
  idx int;
  updates jsonb := $vkd_kahraman_page_updates$[{"slug":"turk-dunyasi-kahramanlari","title":"Türk Dünyası Kahramanları","bodyHtml":"<link rel=\"stylesheet\" href=\"https://fonts.googleapis.com/css2?family=Nunito+Sans:wght@400;600;700;800&family=Merriweather:ital,wght@0,400;0,700;1,400&display=swap\">\n<style>\r\n/* TÜRK DÜNYASI KAHRAMANLARI - ÖZEL TASARIM */\r\n.vkv-turk-dunya-wrapper {\r\n  --vkv-r: #8C1A2E; \r\n  --vkv-g: #C9A84C; \r\n  --vkv-blue: #00B5E2; /* Gökbayrak Mavisi */\r\n  --vkv-dk: #0D1117;\r\n  --vkv-t1: #1A1F28;\r\n  --vkv-t2: #4A5568;\r\n  --vkv-bg: #F0F4F8;\r\n  font-family: 'Nunito Sans', sans-serif;\r\n  background: var(--vkv-bg);\r\n  color: var(--vkv-t1);\r\n  line-height: 1.6;\r\n}\r\n\r\n/* Gök Mavisi ve Bordo Hero Alanı */\r\n.td-hero {\r\n  background: linear-gradient(rgba(13, 17, 23, 0.8), rgba(13, 17, 23, 0.85)), \r\n              url('https://images.unsplash.com/photo-1523363290077-9ca03fb286b8?q=80&w=2000');\r\n  background-size: cover;\r\n  background-position: center;\r\n  padding: 120px 20px;\r\n  text-align: center;\r\n  color: #fff;\r\n  border-bottom: 5px solid var(--vkv-blue);\r\n}\r\n\r\n.td-hero h1 { font-family: 'Merriweather', serif; font-size: clamp(2rem, 5vw, 3.5rem); margin-bottom: 20px; }\r\n.td-hero h1 em { color: var(--vkv-blue); font-style: italic; }\r\n.td-hero p { max-width: 850px; margin: 0 auto; opacity: 0.9; font-size: 1.15rem; }\r\n\r\n/* Bölge Başlıkları */\r\n.td-region-title {\r\n  text-align: center;\r\n  margin: 60px 0 40px;\r\n  position: relative;\r\n}\r\n.td-region-title h2 {\r\n  font-family: 'Merriweather', serif;\r\n  font-size: 2rem;\r\n  color: var(--vkv-r);\r\n  display: inline-block;\r\n  background: var(--vkv-bg);\r\n  padding: 0 30px;\r\n  position: relative;\r\n  z-index: 2;\r\n}\r\n.td-region-title::after {\r\n  content: '';\r\n  position: absolute;\r\n  left: 0;\r\n  top: 50%;\r\n  width: 100%;\r\n  height: 2px;\r\n  background: var(--vkv-bd, #E4E0D8);\r\n  z-index: 1;\r\n}\r\n\r\n/* Kahraman Kartları */\r\n.td-container { max-width: 1300px; margin: 0 auto; padding: 0 20px 80px; }\r\n.td-grid {\r\n  display: grid;\r\n  grid-template-columns: repeat(auto-fit, minmax(350px, 1fr));\r\n  gap: 30px;\r\n}\r\n\r\n.td-card {\r\n  background: #fff;\r\n  border-radius: 12px;\r\n  overflow: hidden;\r\n  box-shadow: 0 10px 25px rgba(0,0,0,0.05);\r\n  transition: 0.3s;\r\n  display: flex;\r\n  flex-direction: column;\r\n  border: 1px solid rgba(0,0,0,0.05);\r\n}\r\n\r\n.td-card:hover { transform: translateY(-10px); box-shadow: 0 20px 40px rgba(0,181,226,0.15); border-color: var(--vkv-blue); }\r\n\r\n.td-card-flag {\r\n  height: 8px;\r\n  background: var(--vkv-blue);\r\n}\r\n\r\n.td-body { padding: 30px; }\r\n.td-meta { display: flex; justify-content: space-between; align-items: center; margin-bottom: 15px; }\r\n.td-tag { background: var(--vkv-rl, rgba(140,26,46,0.1)); color: var(--vkv-r); font-size: 10px; font-weight: 800; padding: 4px 12px; border-radius: 4px; text-transform: uppercase; }\r\n.td-country { font-size: 12px; font-weight: 700; color: var(--vkv-t3); }\r\n\r\n.td-name { font-family: 'Merriweather', serif; font-size: 20px; margin-bottom: 15px; color: var(--vkv-dk); }\r\n.td-desc { font-size: 14px; color: var(--vkv-t2); line-height: 1.8; margin-bottom: 20px; }\r\n\r\n.td-quote { \r\n  font-style: italic; \r\n  font-size: 13px; \r\n  color: var(--vkv-r); \r\n  border-left: 3px solid var(--vkv-g); \r\n  padding-left: 15px;\r\n  margin-top: auto;\r\n}\r\n\r\n/* Alt Bilgi */\r\n.td-footer { background: var(--vkv-dk); color: #fff; padding: 60px 20px; text-align: center; }\r\n\r\n@media (max-width: 768px) {\r\n  .td-grid { grid-template-columns: 1fr; }\r\n}\r\n</style>\r\n\r\n<div class=\"vkv-turk-dunya-wrapper\">\r\n  <section class=\"td-hero\">\r\n    <div style=\"font-size: 50px; margin-bottom: 20px;\">🌍</div>\r\n    <h1>Sınırları Aşan Vefa: <em>Türk Dünyası Kahramanları</em></h1>\r\n    <p>Adriyatik'ten Çin Seddi'ne, Kırım'dan Kıbrıs'a kadar; hürriyet meşalesini elden ele taşıyan, kardeş coğrafyalarımızın kaderini değiştiren aziz büyüklerimizin hatırasına.</p>\r\n  </section>\r\n\r\n  <div class=\"td-container\">\r\n    \r\n    <div class=\"td-region-title\"><h2>Kafkasya ve Orta Asya</h2></div>\r\n    <div class=\"td-grid\">\r\n      <div class=\"td-card\">\r\n        <div class=\"td-card-flag\" style=\"background: #E41B17;\"></div> <div class=\"td-body\">\r\n          <div class=\"td-meta\"><span class=\"td-tag\">Kafkas İslam Ordusu</span><span class=\"td-country\">AZERBAYCAN</span></div>\r\n          <h3 class=\"td-name\">Nuri (Killigil) Paşa</h3>\r\n          <p class=\"td-desc\">1918 yılında Bakü'yü Bolşevik ve Ermeni işgalinden kurtaran Kafkas İslam Ordusu'nun efsanevi komutanı. Azerbaycan'ın bağımsızlık tarihindeki en kilit isimlerden biridir.</p>\r\n          <p class=\"td-quote\">\"Bakü'nün kurtuluşu, sadece bir şehrin değil, bir milletin uyanışıdır.\"</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"td-card\">\r\n        <div class=\"td-card-flag\" style=\"background: #00B5E2;\"></div> <div class=\"td-body\">\r\n          <div class=\"td-meta\"><span class=\"td-tag\">Hürriyet Mücahidi</span><span class=\"td-country\">DOĞU TÜRKİSTAN</span></div>\r\n          <h3 class=\"td-name\">Osman Batur</h3>\r\n          <p class=\"td-desc\">Doğu Türkistan'ın bağımsızlığı için Çin baskısına karşı destansı bir direniş gösteren halk kahramanı. \"Batur\" unvanını halkından alan cesaret sembolü.</p>\r\n          <p class=\"td-quote\">\"Ben can verebilirim ama milletim hür yaşamalıdır.\"</p>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"td-region-title\"><h2>Akdeniz ve Balkanlar</h2></div>\r\n    <div class=\"td-grid\">\r\n      <div class=\"td-card\">\r\n        <div class=\"td-card-flag\" style=\"background: #E41B17;\"></div>\r\n        <div class=\"td-body\">\r\n          <div class=\"td-meta\"><span class=\"td-tag\">Kurucu Cumhurbaşkanı</span><span class=\"td-country\">KKTC</span></div>\r\n          <h3 class=\"td-name\">Rauf Raif Denktaş</h3>\r\n          <p class=\"td-desc\">Kıbrıs Türklerinin varoluş mücadelesinin lideri. TMT'nin (Türk Mukavemet Teşkilatı) kurulmasında ve Kuzey Kıbrıs Türk Cumhuriyeti'nin ilanında ömrünü vakfeden devlet adamı.</p>\r\n          <p class=\"td-quote\">\"Benim iki bayrağım var; biri al sancak, biri Kıbrıs'ın ak sancağı.\"</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"td-card\">\r\n        <div class=\"td-card-flag\" style=\"background: #2ecc71;\"></div> <div class=\"td-body\">\r\n          <div class=\"td-meta\"><span class=\"td-tag\">Dava Adamı</span><span class=\"td-country\">BATI TRAKYA</span></div>\r\n          <h3 class=\"td-name\">Dr. Sadık Ahmet</h3>\r\n          <p class=\"td-desc\">Batı Trakya Türk azınlığının haklarını dünyaya duyurmak için hapis yatma pahasına \"Türk\" olduğunu haykıran, mücadelesiyle Yunanistan'daki soydaşlarımıza ses olan lider.</p>\r\n          <p class=\"td-quote\">\"Sırf Türk olduğum için hapse götürülürsem, bu benim için ancak şereftir.\"</p>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n    <div class=\"td-region-title\"><h2>Kırım ve Gönül Coğrafyamız</h2></div>\r\n    <div class=\"td-grid\">\r\n      <div class=\"td-card\">\r\n        <div class=\"td-card-flag\" style=\"background: #00B5E2;\"></div>\r\n        <div class=\"td-body\">\r\n          <div class=\"td-meta\"><span class=\"td-tag\">Fikir Önderi</span><span class=\"td-country\">KIRIM</span></div>\r\n          <h3 class=\"td-name\">İsmail Gaspıralı</h3>\r\n          <p class=\"td-desc\">Türk dünyasının birliği için \"Dilde, Fikirde, İş'te Birlik\" şiarını ortaya atan, Tercüman gazetesiyle tüm Türk halklarını ortak bir paydada buluşturan vizyoner kahraman.</p>\r\n          <p class=\"td-quote\">\"Dilde birlik, fikirde birlik, iş'te birlik!\"</p>\r\n        </div>\r\n      </div>\r\n\r\n      <div class=\"td-card\">\r\n        <div class=\"td-card-flag\" style=\"background: var(--vkv-dk);\"></div>\r\n        <div class=\"td-body\">\r\n          <div class=\"td-meta\"><span class=\"td-tag\">Edebiyatın Sesi</span><span class=\"td-country\">KIRIM / TATAR</span></div>\r\n          <h3 class=\"td-name\">Cengiz Dağcı</h3>\r\n          <p class=\"td-desc\">Kırım Tatarlarının yaşadığı sürgünü ve acıları dünyaya edebiyat yoluyla anlatan, vatan hasretini her satırında işleyerek hafızaları diri tutan kalem kahramanı.</p>\r\n          <p class=\"td-quote\">\"Vatanını kaybeden adam, her şeyini kaybetmiştir.\"</p>\r\n        </div>\r\n      </div>\r\n    </div>\r\n\r\n  </div>\r\n\r\n  <section class=\"td-footer\">\r\n    <div style=\"max-width: 800px; margin: 0 auto;\">\r\n      <h2 style=\"font-family: 'Merriweather', serif; color: var(--vkv-g); margin-bottom: 20px;\">Tek Millet, Yedi Devlet</h2>\r\n      <p style=\"opacity: 0.8;\">Vakfımız, bu asil kahramanların bıraktığı mirasa sahip çıkarak; Türk dünyasının her köşesindeki gazilerimize ve şehit yakınlarımıza ulaşmaya devam etmektedir.</p>\r\n      <a href=\"/bagis\" style=\"display: inline-block; background: var(--vkv-r); color: #fff; padding: 15px 45px; border-radius: 5px; font-weight: 800; text-decoration: none; margin-top: 30px;\">❤️ BİRLİK İÇİN DESTEK OL</a>\r\n    </div>\r\n  </section>\r\n</div>"},{"slug":"vefa-galerisi","title":"Vefa Galerisi","bodyHtml":"<link rel=\"stylesheet\" href=\"https://fonts.googleapis.com/css2?family=Nunito+Sans:wght@400;600;700;800&family=Merriweather:ital,wght@0,400;0,700;1,400&display=swap\">\n<link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/4.7.0/css/font-awesome.min.css\">\n<style>\r\n/* ONUR SAYFASI - ZENGİNLEŞTİRİLMİŞ TAM TASARIM */\r\n.vkv-honor-premium {\r\n  --vkv-r: #8C1A2E; --vkv-rd: #6E1222; --vkv-rl: rgba(140,26,46,.08);\r\n  --vkv-g: #C9A84C; --vkv-gl: rgba(201,168,76,.15);\r\n  --vkv-dk: #0D1117; --vkv-dk2: #161B22;\r\n  --vkv-t1: #1A1F28; --vkv-t2: #4A5568; --vkv-t3: #8B949E;\r\n  --vkv-bg: #FAFAF8;\r\n  font-family: 'Nunito Sans', sans-serif;\r\n  background: var(--vkv-bg);\r\n  color: var(--vkv-t1);\r\n  line-height: 1.7;\r\n}\r\n\r\n/* Hero - Onur Kürsüsü */\r\n.hp-hero {\r\n  background: linear-gradient(rgba(13, 17, 23, 0.9), rgba(13, 17, 23, 0.92)), \r\n              url('https://images.unsplash.com/photo-1590234900693-80e793910543?q=80&w=2000');\r\n  background-size: cover; background-position: center;\r\n  padding: 120px 20px; text-align: center; color: #fff;\r\n  border-bottom: 5px solid var(--vkv-r);\r\n}\r\n.hp-hero h1 { font-family: 'Merriweather', serif; font-size: clamp(2.5rem, 5vw, 4rem); margin-bottom: 20px; }\r\n.hp-hero p { max-width: 850px; margin: 0 auto; font-size: 1.2rem; opacity: 0.9; font-style: italic; color: var(--vkv-g); }\r\n\r\n/* İstatistik / Vurgu Bandı */\r\n.hp-stats { background: #fff; padding: 30px 20px; border-bottom: 1px solid #eee; }\r\n.hp-stats-w { max-width: 1200px; margin: 0 auto; display: flex; justify-content: space-around; flex-wrap: wrap; gap: 20px; }\r\n.hp-stat-item { text-align: center; }\r\n.hp-stat-num { font-size: 24px; font-weight: 800; color: var(--vkv-r); display: block; }\r\n.hp-stat-lbl { font-size: 11px; font-weight: 700; color: var(--vkv-t3); text-transform: uppercase; letter-spacing: 1px; }\r\n\r\n/* Onur Gridi - 12 Kahraman */\r\n.hp-container { max-width: 1300px; margin: 0 auto; padding: 80px 20px; }\r\n.hp-grid-12 {\r\n  display: grid;\r\n  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));\r\n  gap: 30px;\r\n}\r\n\r\n.hp-card {\r\n  background: #fff; border-radius: 15px; padding: 45px 30px;\r\n  box-shadow: 0 10px 30px rgba(0,0,0,0.04);\r\n  border: 1px solid #E4E0D8; position: relative;\r\n  transition: 0.4s; overflow: hidden;\r\n}\r\n.hp-card:hover { transform: translateY(-10px); border-color: var(--vkv-g); box-shadow: 0 20px 45px rgba(0,0,0,0.1); }\r\n\r\n.hp-card::before {\r\n  content: '🎖️'; position: absolute; top: -10px; right: -10px;\r\n  font-size: 80px; opacity: 0.03; transform: rotate(15deg);\r\n}\r\n\r\n.hp-tag { \r\n  display: inline-block; background: var(--vkv-rl); color: var(--vkv-r); \r\n  font-size: 10px; font-weight: 800; padding: 4px 14px; border-radius: 4px; \r\n  margin-bottom: 15px; text-transform: uppercase; border-left: 3px solid var(--vkv-r);\r\n}\r\n\r\n.hp-name { font-family: 'Merriweather', serif; font-size: 22px; margin-bottom: 12px; color: var(--vkv-dk); }\r\n.hp-story { font-size: 14px; color: var(--vkv-t2); font-style: italic; margin-bottom: 20px; }\r\n\r\n/* Meslek Onuru Vurgusu */\r\n.hp-occup-info { font-size: 12px; color: var(--vkv-t3); border-top: 1px solid #f0f0f0; padding-top: 15px; }\r\n.hp-occup-info strong { color: var(--vkv-r); }\r\n\r\n/* Neden Onlara Kahraman Diyoruz? */\r\n.hp-why { background: var(--vkv-dk); color: #fff; padding: 100px 20px; text-align: center; }\r\n.hp-why-w { max-width: 850px; margin: 0 auto; }\r\n.hp-why h2 { font-family: 'Merriweather', serif; font-size: 2.5rem; color: var(--vkv-g); margin-bottom: 25px; }\r\n.hp-why p { font-size: 1.15rem; line-height: 1.8; opacity: 0.8; }\r\n\r\n/* Final Bandı */\r\n.hp-footer { background: var(--vkv-r); color: #fff; padding: 60px 20px; text-align: center; }\r\n.hp-btn {\r\n  display: inline-block; background: var(--vkv-g); color: #000; padding: 18px 50px;\r\n  border-radius: 5px; font-weight: 800; text-decoration: none; margin-top: 30px;\r\n  transition: 0.3s; box-shadow: 0 10px 20px rgba(0,0,0,0.2);\r\n}\r\n.hp-btn:hover { background: #fff; color: var(--vkv-r); transform: scale(1.05); }\r\n\r\n@media (max-width: 768px) { .hp-grid-12 { grid-template-columns: 1fr; } }\r\n</style>\r\n\r\n<div class=\"vkv-honor-premium\">\r\n  <section class=\"hp-hero\">\r\n    <div style=\"font-size: 50px; margin-bottom: 20px;\">🛡️</div>\r\n    <h1>Ölümsüzleşen Emanetler: <em>Vefa Galerisi</em></h1>\r\n    <p>\"Kahramanlık; saldırıp bir daha dönmemektir...\" Onlar, her sabah üniformalarını \"Vatan Sağ Olsun\" diyerek giyenlerin ölümsüz temsilcileridir.</p>\r\n  </section>\r\n\r\n  <div class=\"hp-stats\">\r\n    <div class=\"hp-stats-w\">\r\n      <div class=\"hp-stat-item\"><span class=\"hp-stat-num\">12</span><span class=\"hp-stat-lbl\">SEMBOL İSİM</span></div>\r\n      <div class=\"hp-stat-item\"><span class=\"hp-stat-num\">9+</span><span class=\"hp-stat-lbl\">MESLEK GRUBU</span></div>\r\n      <div class=\"hp-stat-item\"><span class=\"hp-stat-num\">∞</span><span class=\"hp-stat-lbl\">SONSUZ MİNNET</span></div>\r\n    </div>\r\n  </div>\r\n\r\n  <div class=\"hp-container\">\r\n    <div class=\"hp-grid-12\">\r\n      \r\n      <div class=\"hp-card\">\r\n        <span class=\"hp-tag\">EMNİYET TEŞKİLATI</span>\r\n        <h3 class=\"hp-name\">Fethi Sekin</h3>\r\n        <p class=\"hp-story\">İzmir Adliyesi önünde mermisi bitene kadar teröristlerle çatışarak büyük bir katliamı önleyen kahraman polisimiz.</p>\r\n        <div class=\"hp-occup-info\"><strong>Görev Bilinci:</strong> Şehirlerimizin huzuru ve asayişi için canını siper eden emniyet güçlerimizin onurudur.</div>\r\n      </div>\r\n\r\n      <div class=\"hp-card\">\r\n        <span class=\"hp-tag\">EĞİTİM NEFERİ</span>\r\n        <h3 class=\"hp-name\">Şenay Aybüke Yalçın</h3>\r\n        <p class=\"hp-story\">\"Vatanın geleceği eğitimdir\" diyerek Batman'da görev yaparken karne günü şehit edilen genç öğretmenimiz.</p>\r\n        <div class=\"hp-occup-info\"><strong>Eğitim Aşkı:</strong> En uzak köylere ışık götüren, cehaletle savaşırken şehit düşen öğretmenlerimizin sembolüdür.</div>\r\n      </div>\r\n\r\n      <div class=\"hp-card\">\r\n        <span class=\"hp-tag\">TÜRK SİLAHLI KUVVETLERİ</span>\r\n        <h3 class=\"hp-name\">Ömer Halisdemir</h3>\r\n        <p class=\"hp-story\">Darbe girişiminin seyrini değiştiren o kritik mermiyi, sonunda şahadet olduğunu bilerek sıkan sadakat abidesi.</p>\r\n        <div class=\"hp-occup-info\"><strong>Askeri Disiplin:</strong> Sınır güvenliğimizden terörle mücadeleye kadar her alanda en önde olan Mehmetçik'in iradesidir.</div>\r\n      </div>\r\n\r\n      <div class=\"hp-card\">\r\n        <span class=\"hp-tag\">SİVİL / YEREL KAHRAMAN</span>\r\n        <h3 class=\"hp-name\">Eren Bülbül</h3>\r\n        <p class=\"hp-story\">\"İyi ki varsın Eren\"... Henüz 15 yaşında vatan toprağını teröristlerden korumak için askerine rehberlik eden yiğit.</p>\r\n        <div class=\"hp-occup-info\"><strong>Sivil İrade:</strong> Vatan savunmasının sadece üniformayla değil, her bir ferdin yüreğiyle yapıldığının kanıtıdır.</div>\r\n      </div>\r\n\r\n      <div class=\"hp-card\">\r\n        <span class=\"hp-tag\">YARGI MENSUBU</span>\r\n        <h3 class=\"hp-name\">Mehmet Selim Kiraz</h3>\r\n        <p class=\"hp-story\">İstanbul Adliyesi'nde görevi başında adaleti savunurken şehit edilen, hukuk tarihimizin sarsılmaz kalemi.</p>\r\n        <div class=\"hp-occup-info\"><strong>Adalet İnancı:</strong> Hukukun üstünlüğü ve adaletin tesisi için canı pahasına görev yapan yargı camiasının onurudur.</div>\r\n      </div>\r\n\r\n      <div class=\"hp-card\">\r\n        <span class=\"hp-tag\">ÖĞRETMEN</span>\r\n        <h3 class=\"hp-name\">Necmettin Yılmaz</h3>\r\n        <p class=\"hp-story\">Gümüşhane yolunda kaçırılarak şehit edilen, tek amacı çocukları aydınlatmak olan vatan sevdalısı eğitimci.</p>\r\n        <div class=\"hp-occup-info\"><strong>Fedakarlık:</strong> Zor şartlar altında dahi \"vatan görevi\" diyerek sınıfa giren öğretmenlerimizin sessiz çığlığıdır.</div>\r\n      </div>\r\n\r\n      <div class=\"hp-card\">\r\n        <span class=\"hp-tag\">İTFAİYE TEŞKİLATI</span>\r\n        <h3 class=\"hp-name\">Gökhan Aksu</h3>\r\n        <p class=\"hp-story\">Başkalarını yaşatmak için alevlerin içine giren, her kurtardığı canı vatan borcu bilen cesur itfaiye eri.</p>\r\n        <div class=\"hp-occup-info\"><strong>Cesaret:</strong> Herkesin kaçtığı alevlere başkaları için koşan itfaiyecilerimizin kahramanlığıdır.</div>\r\n      </div>\r\n\r\n      <div class=\"hp-card\">\r\n        <span class=\"hp-tag\">ORMAN MUHAFAZA GÖNÜLLÜSÜ</span>\r\n        <h3 class=\"hp-name\">Şahin Akdemir</h3>\r\n        <p class=\"hp-story\">Büyük orman yangınlarında ekiplere su taşırken alevlerin arasında kalarak yeşil vatan uğruna can veren genç.</p>\r\n        <div class=\"hp-occup-info\"><strong>Yeşil Vatan:</strong> Toprağın ağacını ve doğasını korumayı \"vatan savunması\" görenlerin temsilcisidir.</div>\r\n      </div>\r\n\r\n      <div class=\"hp-card\">\r\n        <span class=\"hp-tag\">HAVA KUVVETLERİ</span>\r\n        <h3 class=\"hp-name\">Cengiz Topel</h3>\r\n        <p class=\"hp-story\">Kıbrıs semalarında uçağı düşürülen ve işkenceyle şehit edilen, göklerdeki ilk hava harp şehidimiz.</p>\r\n        <div class=\"hp-occup-info\"><strong>Hava Savunması:</strong> Mavi vatanın semalarında gece gündüz nöbet tutan pilotlarımızın çelikleşmiş iradesidir.</div>\r\n      </div>\r\n\r\n      <div class=\"hp-card\">\r\n        <span class=\"hp-tag\">ÇANAKKALE KAHRAMANI</span>\r\n        <h3 class=\"hp-name\">Ezineli Yahya Çavuş</h3>\r\n        <p class=\"hp-story\">Ertuğrul Koyu'nda 63 kişilik takımıyla koca bir orduyu durduran, Çanakkale destanının sönmeyen ateşi.</p>\r\n        <div class=\"hp-occup-info\"><strong>Tarihi Miras:</strong> Geçmişten bugüne vatanın her karışında kanı olan atalarımızın ruhudur.</div>\r\n      </div>\r\n\r\n      <div class=\"hp-card\">\r\n        <span class=\"hp-tag\">İSTİKLAL KADINI</span>\r\n        <h3 class=\"hp-name\">Şerife Bacı</h3>\r\n        <p class=\"hp-story\">Kastamonu'da cephane ıslanmasın diye çocuğunun battaniyesini mermilere saran, donarak şehadete yürüyen ana.</p>\r\n        <div class=\"hp-occup-info\"><strong>Lojistik Destek:</strong> Cephe gerisinde cepheden daha büyük yük sırtlayan kahraman Türk kadınının simgesidir.</div>\r\n      </div>\r\n\r\n      <div class=\"hp-card\">\r\n        <span class=\"hp-tag\">TOPÇU ONBAŞI</span>\r\n        <h3 class=\"hp-name\">Seyit Çabuk</h3>\r\n        <p class=\"hp-story\">215 kiloluk mermiyi \"Ya Allah\" diyerek sırtlayan ve bir imparatorluğun kaderini değiştiren gazi dev.</p>\r\n        <div class=\"hp-occup-info\"><strong>Azim ve İnanç:</strong> Teknik imkansızlıklara karşı imanın ve fiziksel gücün zaferidir.</div>\r\n      </div>\r\n\r\n    </div>\r\n  </div>\r\n\r\n  <section class=\"hp-why\">\r\n    <div class=\"hp-why-w\">\r\n      <h2>Neden Onlara Kahraman Diyoruz?</h2>\r\n      <p>Kahramanlık sadece bir olay anında gösterilen cesaret değildir. Kahramanlık; toplumun refahı için her sabah o üniformayı, o önlüğü veya o kaskı <strong>\"başıma bir şey gelebilir\"</strong> bilinciyle giymektir. Onlar, bizim bugün güvenle okula gidebilmemizi, huzurla uyuyabilmemizi sağlayan asil ruhlardır.</p>\r\n    </div>\r\n  </section>\r\n\r\n  <section class=\"hp-footer\">\r\n    <div style=\"max-width: 900px; margin: 0 auto;\">\r\n      <h2 style=\"font-family: 'Merriweather', serif; font-size: 2.2rem; margin-bottom: 10px;\">Hatıraları Emanetimizdir</h2>\r\n      <p style=\"opacity: 0.8;\">Şehitlerimizin geride bıraktığı aileleri ve kahraman gazilerimiz için bize destek olun.</p>\r\n      <a href=\"/bagis\" class=\"hp-btn\">❤️ KAHRAMANLARA VEFA BORCUNU ÖDE</a>\r\n    </div>\r\n  </section>\r\n</div>"}]$vkd_kahraman_page_updates$::jsonb;
  new_menu_item jsonb := $vkd_kahraman_menu_item${"id":"vkd-menu-kah-vefa","label":"Vefa Galerisi","href":"/vefa-galerisi","parentId":"vkd-menu-kahramanlar","enabled":true}$vkd_kahraman_menu_item$::jsonb;
BEGIN
  SELECT (layout_json::jsonb)->'hmExtraPages' INTO pages FROM hm_news_sites WHERE slug = 'vkd';
  IF pages IS NULL THEN
    RETURN; -- fresh DB: vkd sitesi yok (VKD hmExtraPages not found)
  END IF;

  FOR upd IN SELECT * FROM jsonb_to_recordset(updates) AS x(slug text, title text, "bodyHtml" text)
  LOOP
    idx := NULL;
    FOR i IN 0..jsonb_array_length(pages) - 1 LOOP
      IF lower(trim(pages->i->>'slug')) = lower(trim(upd.slug)) THEN
        idx := i;
        EXIT;
      END IF;
    END LOOP;

    IF idx IS NULL THEN
      pages := pages || jsonb_build_array(
        jsonb_build_object(
          'id', 'vkd-page-' || replace(upd.slug, ' ', '-'),
          'title', upd.title,
          'slug', upd.slug,
          'bodyHtml', upd."bodyHtml",
          'enabled', true,
          'fullWidth', true
        )
      );
    ELSE
      pages := jsonb_set(
        jsonb_set(
          jsonb_set(pages, ARRAY[idx::text, 'bodyHtml'], to_jsonb(upd."bodyHtml"), true),
          ARRAY[idx::text, 'title'],
          to_jsonb(upd.title),
          true
        ),
        ARRAY[idx::text, 'enabled'],
        'true'::jsonb,
        true
      );
    END IF;
  END LOOP;

  SELECT (layout_json::jsonb)->'hmCorporateMenuItems' INTO menu FROM hm_news_sites WHERE slug = 'vkd';
  IF menu IS NULL THEN
    menu := '[]'::jsonb;
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM jsonb_array_elements(menu) elem
    WHERE elem->>'id' = new_menu_item->>'id'
       OR lower(trim(elem->>'href')) = lower(trim(new_menu_item->>'href'))
  ) THEN
    menu := menu || jsonb_build_array(new_menu_item);
  END IF;

  UPDATE hm_news_sites
  SET
    layout_json = (jsonb_set(
      jsonb_set(layout_json::jsonb, '{hmExtraPages}', pages, true),
      '{hmCorporateMenuItems}',
      menu,
      true
    ))::text,
    updated_at = now()
  WHERE slug = 'vkd';
END $$;
